import zipfile
import xml.etree.ElementTree as ET

files = [
    "/Users/samuel/Documents/MAIPA/Multi-Agent_System_Architecture_v2.docx",
    "/Users/samuel/Documents/MAIPA/Data_Database_Architecture_v2.docx",
    "/Users/samuel/Documents/MAIPA/LLM_Synthesis_Agent_Spec.docx",
    "/Users/samuel/Documents/MAIPA/Product_Overview_User_Experience_v2.docx"
]

def extract_text_from_docx\(docx_path\):
    """Extract all text from a .docx file"""
    text = []
    try:
        with zipfile.ZipFile\(docx_path, 'r'\) as zip_ref:
            xml_content = zip_ref.read\('word/document.xml'\)

        # Parse the XML
        root = ET.fromstring\(xml_content\)

        # Define namespaces
        namespaces = {
            'w': 'http://schemas.openxmlformats.org/wordprocessingml/2006/main'
        }

        # Extract text from all text elements
        for paragraph in root.findall\('.//w:p', namespaces\):
            para_text = []
            for text_elem in paragraph.findall\('.//w:t', namespaces\):
                if text_elem.text:
                    para_text.append\(text_elem.text\)
            if para_text:
                text.append\(''.join\(para_text\)\)

        return text
    except Exception as e:
        return [f"Error: {e}"]

for file_path in files:
    print\(f"\\n{'='*80}"\)
    print\(f"FILE: {file_path.split\('/'\)[-1]}"\)
    print\(f"{'='*80}\\n"\)

    text_lines = extract_text_from_docx\(file_path\)
    for line in text_lines:
        print\(line\)
EOF)

