Bash(node -e "
const { createClient } = require\('@supabase/supabase-js'\);
const url = process.env.NEXT_PUBLIC_SUPABASE_URL;
const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
if \(!url || !key\) { console.log\('Missing env vars'\); process.exit\(1\); }
const sb = createClient\(url, key\);
\(async \(\) => {
  // Check latest score date
  const { data: dateRow } = await sb.from\('agent_scores'\).select\('date'\).order\('date', { ascending: false }\).limit\(1\);
  console.log\('Latest score date:', dateRow?.[0]?.date\);

  // Count scores on that date
  const latestDate = dateRow?.[0]?.date;
  if \(!latestDate\) return;

  const { data: scores, error } = await sb.from\('agent_scores'\).select\('ticker, agent_type, score'\).eq\('date', latestDate\).limit\(2000\);
  console.log\('Total scores on latest date:', scores?.length, error?.message\);

  // Check unique tickers
  const tickers = new Set\(scores?.map\(s => s.ticker\)\);
  console.log\('Unique tickers:', tickers.size\);

  // Check agent types
  const types = {};
  scores?.forEach\(s => { types[s.agent_type] = \(types[s.agent_type] || 0\) + 1; }\);
  console.log\('Agent type counts:', types\);

  // Check MARKET ticker
  const market = scores?.filter\(s => s.ticker === 'MARKET' || s.ticker === 'MARKET_CRYPTO'\);
  console.log\('Market regime scores:', market\);
}\)\(\);
" 2>&1)

